class Solution {
    public long minimumSteps(String s) {
        int n = s.length();
        int ones = 0;
        long res = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '1') {
                ones++;
            } else {
                res += ones;
            }
        }
        return res;
    }
}
```
